// Extrai e limpa a resposta gerada pelo Ollama
const dados = $input.first().json;
const resposta = (dados.response || '').trim();

if (!resposta) {
  return [{ json: { resposta: 'Desculpe, no momento não consegui processar sua mensagem. Um atendente humano irá auxiliar em breve.' } }];
}

return [{ json: { resposta } }];
